import json
import boto3
import os
import logging
from typing import Any

logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Allowed origins - explicitly defined for security
# Configure via environment variable as comma-separated list
ALLOWED_ORIGINS = os.environ.get(
    'ALLOWED_ORIGINS',
    'https://app.example.com,https://staging.example.com'
).split(',')

# In development, you can add http://localhost:3000 to the environment variable
# but NEVER use wildcard '*' in production

ALLOWED_METHODS = 'GET,OPTIONS'
ALLOWED_HEADERS = 'Content-Type,Authorization,X-Requested-With'
MAX_AGE = '3600'


def get_cors_origin(event: dict) -> str:
    """
    Validate the request origin against the allowlist and return
    the matching origin, or empty string if not allowed.
    """
    headers = event.get('headers', {}) or {}
    # Headers may be case-insensitive in API Gateway
    request_origin = headers.get('origin') or headers.get('Origin', '')

    if request_origin in ALLOWED_ORIGINS:
        return request_origin

    logger.warning(f"Rejected CORS request from origin: {request_origin}")
    return ''


def build_cors_headers(origin: str) -> dict:
    """Build CORS response headers with validated origin."""
    if not origin:
        return {}

    return {
        'Access-Control-Allow-Origin': origin,
        'Access-Control-Allow-Methods': ALLOWED_METHODS,
        'Access-Control-Allow-Headers': ALLOWED_HEADERS,
        'Access-Control-Max-Age': MAX_AGE,
        'Access-Control-Allow-Credentials': 'true',
        'Vary': 'Origin'
    }


def build_response(status_code: int, body: Any, cors_headers: dict) -> dict:
    """Build a standardized API response."""
    headers = {
        'Content-Type': 'application/json',
        'X-Content-Type-Options': 'nosniff',
        'X-Frame-Options': 'DENY',
        'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
        'Cache-Control': 'no-store',
    }
    headers.update(cors_headers)

    return {
        'statusCode': status_code,
        'headers': headers,
        'body': json.dumps(body)
    }


def validate_user_id(user_id: str) -> bool:
    """Validate user_id format to prevent injection attacks."""
    if not user_id:
        return False
    # Allow only alphanumeric characters and hyphens, max 64 chars
    if len(user_id) > 64:
        return False
    return all(c.isalnum() or c == '-' for c in user_id)


def get_user_data(user_id: str) -> dict:
    """
    Fetch user data from DynamoDB.
    Returns only non-sensitive fields for the frontend.
    """
    dynamodb = boto3.resource('dynamodb')
    table_name = os.environ.get('USERS_TABLE', 'Users')
    table = dynamodb.Table(table_name)

    response = table.get_item(
        Key={'userId': user_id},
        # Only project the fields needed by the frontend - principle of least privilege
        ProjectionExpression='userId, displayName, email, avatarUrl, #r',
        ExpressionAttributeNames={'#r': 'role'}
    )

    item = response.get('Item')
    if not item:
        return None

    # Explicitly construct response to avoid leaking internal fields
    return {
        'userId': item.get('userId', ''),
        'displayName': item.get('displayName', ''),
        'email': item.get('email', ''),
        'avatarUrl': item.get('avatarUrl', ''),
        'role': item.get('role', 'user')
    }


def lambda_handler(event: dict, context: Any) -> dict:
    """
    Main Lambda handler for user data API.

    Supports:
      - GET /users/{userId} - Retrieve user data
      - OPTIONS /users/{userId} - CORS preflight
    """
    logger.info(f"Request received: {event.get('httpMethod')} {event.get('path')}")

    # Validate origin and build CORS headers
    validated_origin = get_cors_origin(event)
    cors_headers = build_cors_headers(validated_origin)

    http_method = event.get('httpMethod', '')

    # Handle CORS preflight
    if http_method == 'OPTIONS':
        if not validated_origin:
            return build_response(403, {'error': 'Origin not allowed'}, {})
        return build_response(200, {}, cors_headers)

    # Only allow GET requests
    if http_method != 'GET':
        return build_response(405, {'error': 'Method not allowed'}, cors_headers)

    # If origin is present but not allowed, reject the request
    request_headers = event.get('headers', {}) or {}
    has_origin = bool(request_headers.get('origin') or request_headers.get('Origin'))
    if has_origin and not validated_origin:
        return build_response(403, {'error': 'Origin not allowed'}, {})

    try:
        # Extract and validate user ID from path parameters
        path_params = event.get('pathParameters', {}) or {}
        user_id = path_params.get('userId', '')

        if not validate_user_id(user_id):
            return build_response(400, {'error': 'Invalid user ID format'}, cors_headers)

        # Fetch user data
        user_data = get_user_data(user_id)

        if user_data is None:
            return build_response(404, {'error': 'User not found'}, cors_headers)

        return build_response(200, {'data': user_data}, cors_headers)

    except Exception as e:
        # Log the full error internally but return a generic message to the client
        logger.error(f"Error processing request: {str(e)}", exc_info=True)
        return build_response(500, {'error': 'Internal server error'}, cors_headers)


